-- テスト用の最小限のBookData.sqliteスキーマ

-- ZBOOKテーブル（必要最小限のフィールドのみ）
CREATE TABLE ZBOOK (
  Z_PK INTEGER PRIMARY KEY,
  Z_ENT INTEGER,
  Z_OPT INTEGER,
  ZBOOKID VARCHAR,
  ZDISPLAYTITLE VARCHAR,
  ZRAWPUBLISHER VARCHAR,
  ZRAWPUBLICATIONDATE INTEGER,
  ZLANGUAGE VARCHAR,
  ZSORTTITLE VARCHAR,
  ZSYNCMETADATAATTRIBUTES BLOB
);

-- ZGROUPテーブル（シリーズマスタ）
CREATE TABLE ZGROUP (
  Z_PK INTEGER PRIMARY KEY,
  ZGROUPID VARCHAR,
  ZDISPLAYNAME VARCHAR
);

-- ZGROUPITEMテーブル（書籍-シリーズ中間テーブル）
CREATE TABLE ZGROUPITEM (
  Z_PK INTEGER PRIMARY KEY,
  ZBOOK INTEGER,
  ZPARENTCONTAINER INTEGER,
  ZPOSITION INTEGER,
  ZPOSITIONLABEL VARCHAR
);

